  ('cpa-moex-01615', 'cpa', 'cpa-moex-101-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '有限公司之董事不為或不能行使職權，致公司受有損害之虞時，法院因利害關係人之聲請，得選任下列 何種人員代行董事之職權？', '["清算人", "破產管理人", "檢查人", "臨時管理人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "62744a62a0e9", "answer_pdf_sha1": "9e21c8458149", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公司法、證券交易法與商業會計法", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01616', 'cpa', 'cpa-moex-101-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '公司如為他公司有限責任股東時，其所有投資總額，公司法第13條訂有上限，但如經股東同意或股東會 決議者外，不在此限，則就股東同意或股東會決議之規定而言，下列敘述何者正確？', '["無限公司經三分之二股東同意", "兩合公司經全體股東同意", "有限公司經全體執行業務股東同意", "股份有限公司經代表已發行股份總數三分之二以上股東出席，以出席股東表決權過半數同意之股東會 決議"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "62744a62a0e9", "answer_pdf_sha1": "9e21c8458149", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公司法、證券交易法與商業會計法", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01617', 'cpa', 'cpa-moex-101-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '有限公司無盈餘時，關於股息及紅利之分派，下列敘述何者正確？', '["得以資本公積之全部或一部分派", "不得分派", "法定盈餘公積已達實收資本額百分之五十時，於其半數內分派", "得以為彌補虧損而提列之特別盈餘公積分派"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "62744a62a0e9", "answer_pdf_sha1": "9e21c8458149", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公司法、證券交易法與商業會計法", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01618', 'cpa', 'cpa-moex-101-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '依現行公司法規定，關於公司債之私募，下列敘述何者錯誤？', '["採發行後報備制", "非公開發行公司不可為之", "私募人數原則上不得超過35人", "無過去年度獲利能力規定之適用"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "62744a62a0e9", "answer_pdf_sha1": "9e21c8458149", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公司法、證券交易法與商業會計法", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01619', 'cpa', 'cpa-moex-101-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '下列何種情形A有限公司之法人格終局消滅？', '["董事長甲死亡，且無繼承人", "主管機關因A公司未於登記後6個月開始營業，或營業後停止營業超過6個月，而予以命令解散", "A有限公司之其他股東以公司經營顯有困難為理由，向法院聲請裁定解散，經法院裁定解散者", "經完成清算程序者"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "62744a62a0e9", "answer_pdf_sha1": "9e21c8458149", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公司法、證券交易法與商業會計法", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01620', 'cpa', 'cpa-moex-101-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '依公司法之規定，對於股份有限公司監察人之設置，下列敘述何者正確？', '["公開發行股票之公司監察人選舉，得依董事會決議採取候選人提名制度", "監察人全體均須在國內有住所", "公開發行股票之公司之監察人須有2人以上", "公司與監察人間之關係，從民法關於僱傭之規定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "62744a62a0e9", "answer_pdf_sha1": "9e21c8458149", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公司法、證券交易法與商業會計法", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL)
